import React, { useState} from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// Importación de Componentes
import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Registro from './components/Registro'; // Asegúrate de crear este archivo
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';
import PanelCliente from './components/PanelCliente';

function App() {
  // 1. ESTADO INICIAL: Leemos de localStorage para mantener la sesión al recargar
  const [isLoggedIn, setIsLoggedIn] = useState(() => {
    return localStorage.getItem('token-falso') !== null;
  });

  const [userRole, setUserRole] = useState(() => {
    return localStorage.getItem('user-role') || null;
  });

  // 2. FUNCIÓN DE CIERRE DE SESIÓN
  const cerrarSesion = () => {
    localStorage.removeItem('token-falso');
    localStorage.removeItem('user-role');
    localStorage.removeItem('user-id');
    localStorage.removeItem('user-name');
    localStorage.removeItem('user-username');
    setIsLoggedIn(false);
    setUserRole(null);
  };

  return (
    <Router>
      <Header 
        isLoggedIn={isLoggedIn} 
        userRole={userRole} 
        cerrarSesion={cerrarSesion} 
      />

      <Routes>
        {/* RUTA PÚBLICA: HOME */}
        <Route path="/" element={<Home isLoggedIn={isLoggedIn} userRole={userRole} />} />

        {/* RUTAS DE AUTENTICACIÓN */}
        <Route 
          path="/login" 
          element={!isLoggedIn ? <Login setIsLoggedIn={setIsLoggedIn} setUserRole={setUserRole} /> : <Navigate to="/" />} 
        />
        <Route 
          path="/registro" 
          element={!isLoggedIn ? <Registro /> : <Navigate to="/" />} 
        />

        {/* RUTAS PRIVADAS: VENDEDOR (Solo si está logueado y es vendedor) */}
        <Route 
          path="/dashboard" 
          element={
            isLoggedIn && userRole === 'vendedor' 
            ? <Dashboard /> 
            : <Navigate to="/login" />
          } 
        />
        <Route 
          path="/ofertas/:id" 
          element={
            isLoggedIn && userRole === 'vendedor' 
            ? <GestionOfertas /> 
            : <Navigate to="/login" />
          } 
        />

        {/* RUTAS PRIVADAS: CLIENTE */}
        <Route 
          path="/panel-cliente" 
          element={
            isLoggedIn && userRole === 'cliente' 
            ? <PanelCliente /> 
            : <Navigate to="/login" />
          } 
        />

        {/* REDIRECCIÓN POR DEFECTO */}
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </Router>
  );
}

export default App;
